mapper.select:
SELECT FROM edu_fund_transaction WHERE user_id = #{userId} AND deleted = 0
AND transaction_type = #{transactionType}
ORDER BY create_time DESC

SELECT t.id, t.user_id, t.transaction_type, t.amount, t.balance_after,
       t.related_id, t.description, t.create_time
FROM edu_fund_transaction t
WHERE t.deleted = 0

    AND t.user_id = #{userId}


    AND t.user_id IN (SELECT su.id FROM sys_user su WHERE su.name LIKE CONCAT('%', #{userName}, '%') AND su.deleted = 0)


    AND t.transaction_type = #{transactionType}


    AND t.create_time >= #{startTime}


    AND t.create_time <= #{endTime}

ORDER BY t.create_time DESC
